define("local_moodec/cart",["core/ajax","core/notification","core/str"],function(Ajax,Notification,Str){"use strict";var SELECTORS={ADD_FORM:'[data-moodec="add-form"]',REMOVE_FORM:'[data-moodec="remove-form"]',TOTAL:'[data-moodec="total"]'};var call=function(methodname,args){return Ajax.call([{methodname:methodname,args:args}])[0];};var onAdd=function(e){e.preventDefault();var form=e.target;var productid=parseInt(form.querySelector('[name="product"]').value,10);var variationField=form.querySelector('[name="variation"]:checked')||form.querySelector('[name="variation"]');var variationid=variationField?parseInt(variationField.value,10):0;call("local_moodec_cart_add",{productid:productid,variationid:variationid}).then(function(){return Str.get_string("addedtocart","local_moodec");}).then(function(message){Notification.addNotification({message:message,type:"success"});return message;}).catch(Notification.exception);};var onRemove=function(e){e.preventDefault();var form=e.target;var itemid=parseInt(form.querySelector('[name="item"]').value,10);call("local_moodec_cart_remove",{itemid:itemid}).then(function(result){var row=form.closest("li");if(row){row.remove();}var total=document.querySelector(SELECTORS.TOTAL);if(total){total.textContent=result.total;}return result;}).catch(Notification.exception);};var init=function(){document.addEventListener("submit",function(e){if(e.target.matches(SELECTORS.ADD_FORM)){onAdd(e);}else if(e.target.matches(SELECTORS.REMOVE_FORM)){onRemove(e);}});};return{init:init};});
